        <SidebarItem title="Settings" icon="settings" fillIcon={false}>
          <SidebarSubItem title="Profile" active={true} onClick={() => {}} />
          <SidebarSubItem title="Account" active={false} onClick={() => {}} />
        </SidebarItem>
      </Sidebar>

      <Page
        namePage="Dashboard"
