};

const NestedBreadcrumb = () => {
  const [toggle, setToggle] = useState(false);

  return (
    <AppShell>
      <Header
        onClick={() => setToggle((prev) => !prev)}
        breadcrumb={
          <Breadcrumb
            items={[
              { pageName: "Settings", href: "#" },
              { pageName: "Account", href: "#" },
              { pageName: "Billing", href: "#" },
