const Animated = () => {
  const [value, setValue] = useState(0);
  const [running, setRunning] = useState(false);
  const [done, setDone] = useState(false);
  const [failed, setFailed] = useState(false);

  const start = () => {
    setValue(0);
    setDone(false);
    setFailed(false);
    setRunning(true);
  };

  useEffect(() => {
    if (!running) return;
    if (value >= 100) {
      setRunning(false);
      setDone(true);
      return;
    }
    const timer = setTimeout(
      () =>
        setValue((prev) =>
          Math.min(prev + Math.floor(Math.random() * 12) + 3, 100),
        ),
      200,
    );
    return () => clearTimeout(timer);
  }, [running, value]);

  const statusLabel = done
    ? "Upload concluído!"
    : failed
      ? "Upload falhou."
      : running
        ? `${value}%`
        : "Aguardando início...";

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        gap: "var(--s-spacing-x-small)",
      }}
    >
      <div style={{ display: "flex", justifyContent: "space-between" }}>
        <small>{statusLabel}</small>
      </div>
      <Progress value={value} error={failed} />
      <div
        style={{
          display: "flex",
          gap: "var(--s-spacing-xx-small)",
          width: "fit-content",
        }}
      >
        <Button onClick={start} disabled={running}>
          Iniciar
        </Button>
        <Button
          onClick={() => {
            setRunning(false);
            setFailed(true);
          }}
          disabled={!running}
          variant="warning"
        >
          Falhar
        </Button>
      </div>
    </div>
  );
};

const MultiStep = () => {
  const steps = ["Dados pessoais", "Endereço", "Pagamento", "Confirmação"];
  const [current, setCurrent] = useState(0);
  const progress = Math.round((current / (steps.length - 1)) * 100);

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        gap: "var(--s-spacing-x-small)",
      }}
    >
      <div style={{ display: "flex", justifyContent: "space-between" }}>
        <small>{steps[current]}</small>
        <small>
          Etapa {current + 1} de {steps.length}
        </small>
      </div>
      <Progress value={progress} />
      <div
        style={{
          display: "flex",
          gap: "var(--s-spacing-xx-small)",
          width: "fit-content",
        }}
      >
        <Button
          onClick={() => setCurrent((p) => Math.max(0, p - 1))}
          disabled={current === 0}
          variant="secondary"
        >
          Voltar
        </Button>
        <Button
          onClick={() => setCurrent((p) => Math.min(steps.length - 1, p + 1))}
          disabled={current === steps.length - 1}
          variant="primary"
        >
          Avançar
        </Button>
      </div>
    </div>
  );
};

